      <div className="border-t border-stone-800/50 pt-12">
        <div className="flex justify-between items-center mb-10">
          <h3 className="text-xl font-black text-stone-200 uppercase tracking-tighter">Students Registry</h3>
          <button onClick={() => onFormChange({ students: [...formData.students, { id: crypto.randomUUID(), name: '', email: '', solutionFiles: [], reportTemplate: '' }] })} className="bg-white/5 hover:bg-white/10 border border-white/10 px-8 py-3 rounded-2xl text-[11px] font-black text-stone-200 transition-all flex items-center shadow-lg">
            <PlusCircleIcon className="w-5 h-5 mr-3 text-sky-500" /> New Student
          </button>
        </div>

        <div className="space-y-5 max-h-[25rem] overflow-y-auto pr-4 scrollbar-thin">
