            <div className="flex items-center gap-3">
               <span className="text-[9px] text-sky-500 font-black animate-pulse uppercase">Searching Guidelines...</span>
               <LoadingSpinnerIcon className="w-5 h-5 text-sky-500 animate-spin" />
            </div>
